import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

const LOGO_BASE64 = "data:image/png;base64,";

export const generateMonthlyReport = (
  month: string,
  transactions: any[],
  scope: 'agency' | 'subaccount' | 'admin',
  entityName: string = '',
  parentName: string = ''
) => {
  const doc = new jsPDF('p', 'pt', 'a4');
  const isAgencyScope = scope === 'agency' || scope === 'admin';

  // Dynamic Name Resolution
  let subaccountName = '';
  let agencyName = '';
  
  if (transactions.length > 0) {
     subaccountName = transactions[0].subaccount_name || transactions[0].location_name || '';
     agencyName = transactions[0].agency_name || '';
  }
  
  // Exclude placeholders passed by UI
  const cleanedEntityName = (entityName === 'My Account' || entityName === 'Agency Report') ? '' : entityName;
  const displayName = subaccountName || cleanedEntityName || (scope === 'subaccount' ? 'Subaccount' : 'Agency Account');
  const finalAgency = agencyName || parentName || '';

  // Format month
  let formattedMonth = month === 'All' ? 'Full History' : month;
  if (month !== 'All' && month.includes('-')) {
    const [yyyy, mm] = month.split('-');
    const dateObj = new Date(Number(yyyy), Number(mm) - 1);
    formattedMonth = dateObj.toLocaleString('default', { month: 'long', year: 'numeric' });
  }

  // Filter transactions to only this month (if not 'All'), and sort oldest to newest
  const monthFiltered = month === 'All' ? transactions : transactions.filter(tx => {
     let rawDate = tx.timestamp || tx.created_at || '';
     return rawDate.startsWith(month);
  });
  
  const sortedTransactions = [...monthFiltered].sort((a, b) => {
    let dateA = new Date(a.timestamp || a.created_at || 0).getTime();
    let dateB = new Date(b.timestamp || b.created_at || 0).getTime();
    return dateA - dateB;
  });

  // --- Document Header ---
  if (LOGO_BASE64) {
      doc.addImage(LOGO_BASE64, 'PNG', 40, 40, 42, 42);
  }

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(22);
  doc.setTextColor(15, 23, 42);
  doc.text('NOLA SMS PRO', 90, 58);

  doc.setFontSize(14);
  doc.setTextColor(37, 99, 235);
  doc.text('CREDIT USAGE REPORT', 90, 76);

  const pageWidth = doc.internal.pageSize.getWidth();
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(10);
  doc.setTextColor(100, 116, 139);
  doc.text(`Generated: ${new Date().toLocaleString()}`, pageWidth - 40, 58, { align: 'right' });

  // --- Account Info ---
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(11);
  doc.setTextColor(100, 116, 139);
  doc.text('ACCOUNT:', 40, 120);
  
  doc.setFontSize(14);
  doc.setTextColor(15, 23, 42);
  doc.text(displayName, 40, 136);

  if (finalAgency && scope !== 'agency') {
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    doc.setTextColor(100, 116, 139);
    doc.text(`Agency: ${finalAgency}`, 40, 150);
  } else if (scope === 'agency') {
    doc.setFont('helvetica', 'normal');
  }

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(11);
  doc.setTextColor(100, 116, 139);
  doc.text('REPORT PERIOD:', pageWidth - 40, 120, { align: 'right' });
  
  doc.setFontSize(14);
  doc.setTextColor(15, 23, 42);
  doc.text(formattedMonth, pageWidth - 40, 136, { align: 'right' });

  // --- Data Processing ---
  let totalDeductions = 0;
  let totalDeposits = 0;
  let totalProfit = 0;

  const tableRows: any[] = [];
  let rowIndex = 1;

  sortedTransactions.forEach((tx) => {
    let rawDate = tx.timestamp || tx.created_at || '';
    let d = rawDate ? new Date(rawDate) : null;
    let dateTimeStr = d ? `${d.toLocaleDateString()} \n${d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}` : '';
    
    let type = String(tx.type || '').replace(/_/g, ' ').toUpperCase();
    let amount = Number(tx.amount || 0);

    if (type === 'SMS USAGE') type = amount < 0 ? 'SMS (SENT)' : 'SMS';
    
    let number = tx.to_number || '';
    let message = tx.message_body || '';
    let description = tx.description || '';
    
    // Auto strip missing elements out of description
    if (!message && description) {
        if (!number && description.includes('SMS to ')) {
            const parts = description.split('SMS to ');
            number = parts[1]?.split(' ')[0] || '';
            if (number) {
                message = description.replace(`SMS to ${number}`, '').trim() || 'No preview available';
            }
        } else {
            message = description;
        }
    }
    
    if (!message) message = "Message preview unavailable";

    let chars = Number(tx.chars || message.length);
    let msgDisplay = `${message}\n[${chars} chars]`;

    let subNameDisplay = tx.subaccount_name || tx.location_name || displayName;
    let agNameDisplay = tx.agency_name || finalAgency || 'N/A';
    let accountDisplay = scope === 'subaccount' ? '-' : `${subNameDisplay}\n(Agency: ${agNameDisplay})`;

    let balance = Number(tx.balance_after || tx.balance || 0);
    
    let amtDisplay = amount > 0 ? `+${amount} credits` : `${amount} credits`;

    const row = [
      String(rowIndex++),
      dateTimeStr,
      accountDisplay,
      type,
      number || '-',
      msgDisplay,
      amtDisplay,
      balance.toLocaleString()
    ];

    if (!isAgencyScope) {
      row.splice(2, 1);
    }

    if (isAgencyScope) {
      const pCost = Number(tx.provider_cost || 0);
      const charged = Number(tx.charged || 0);
      const profit = Number(tx.profit || 0);
      
      row.push(`$${pCost.toFixed(4)}`, `$${charged.toFixed(4)}`, `$${profit.toFixed(4)}`);
      if (tx.type === 'sms_usage') totalProfit += profit;
    }

    if (amount < 0) totalDeductions += Math.abs(amount);
    if (amount > 0) totalDeposits += amount;

    tableRows.push(row);
  });



  // --- Detailed Table ---
  const tableColumn = isAgencyScope 
    ? ["#", "Date/Time", "Account", "Type", "Number", "Message Content", "Amount", "Balance", "Cost", "Charged", "Profit"]
    : ["#", "Date/Time", "Type", "Number", "Message Content", "Amount", "Balance"];

  autoTable(doc, {
    startY: 170,
    head: [tableColumn],
    body: tableRows,
    theme: 'grid',
    headStyles: { fillColor: [15, 23, 42], textColor: 255, fontStyle: 'bold' },
    alternateRowStyles: { fillColor: [248, 250, 252] },
    styles: { fontSize: 8, cellPadding: 5, overflow: 'linebreak', textColor: [51, 65, 85], lineColor: [226, 232, 240], lineWidth: 0.5 },
    columnStyles: isAgencyScope ? {
      0: { cellWidth: 20 },
      5: { cellWidth: 140 }, // Message Content (Agency)
      6: { cellWidth: 45 }, // Amount (Agency)
      7: { cellWidth: 55 }, // Balance (Agency)
    } : {
      0: { cellWidth: 20 },
      4: { cellWidth: 240 }, // Message Content (User)
      5: { cellWidth: 45 }, // Amount (User)
      6: { cellWidth: 55 }, // Balance (User)
    },
    didDrawPage: function () {
      doc.setFontSize(8);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(148, 163, 184);
      
      const pageHeight = doc.internal.pageSize.height || (doc.internal.pageSize as any).getHeight();
      
      doc.text('Note: If any discrepancies are found, please contact support immediately.', 40, pageHeight - 30);
      
      const str = 'Page ' + (doc.internal as any).getNumberOfPages();
      const textWidth = doc.getTextWidth(str);
      doc.text(str, pageWidth - 40 - textWidth, pageHeight - 30);

      doc.setDrawColor(226, 232, 240);
      doc.setLineWidth(0.5);
      doc.line(40, pageHeight - 40, pageWidth - 40, pageHeight - 40);
    }
  });

  const finalY = (doc as any).lastAutoTable?.finalY || 240;

  // --- Bottom Total Summary ---
  doc.setFillColor(241, 245, 249);
  doc.roundedRect(pageWidth - 240, finalY + 20, 200, isAgencyScope ? 90 : 70, 4, 4, 'F');
  
  doc.setFontSize(10);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(15, 23, 42);
  doc.text('MONTHLY REPORT SUMMARY', pageWidth - 230, finalY + 40);

  doc.setFontSize(9);
  doc.setFont('helvetica', 'normal');
  doc.setTextColor(100, 116, 139);
  doc.text('Total Deductions:', pageWidth - 230, finalY + 60);
  doc.text(`-${totalDeductions.toLocaleString()}`, pageWidth - 60, finalY + 60, { align: 'right' });

  doc.text('Total Deposits:', pageWidth - 230, finalY + 75);
  doc.text(`+${totalDeposits.toLocaleString()}`, pageWidth - 60, finalY + 75, { align: 'right' });

  if (isAgencyScope) {
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(21, 128, 61);
    doc.text('Est. Agency Profit:', pageWidth - 230, finalY + 95);
    doc.text(`$${totalProfit.toFixed(4)}`, pageWidth - 60, finalY + 95, { align: 'right' });
  }

  const cleanName = displayName.replace(/[^a-zA-Z0-9]/g, '_');
  doc.save(`Report_${cleanName}_${formattedMonth.replace(/\s+/g, '_')}.pdf`);
};
